/* Read a line from serial into buffer with bounds checking.
 * Returns the number of characters read, or 0 on empty/error.
 * Strips CR/LF terminators. */
static size_t read_command_line(char *buf, size_t buf_size)
{
    size_t pos = 0;
    char c;
    bool overflow = false;

    while (1) {
        if (serial_read_char(&c) != 1) {
            continue;
        }

        /* End of line */
        if (c == '\n' || c == '\r') {
            if (pos == 0) {
                /* Skip leading empty lines */
                continue;
            }
            break;
        }

        /* Ignore non-printable characters except space */
        if (c < 0x20 || c > 0x7E) {
            if (c == '\b' || c == 0x7F) {
                /* Handle backspace */
                if (pos > 0) {
                    pos--;
                    overflow = false;
                }
            }
            continue;
        }

        /* Store character if room remains (reserve 1 byte for null terminator) */
        if (pos < buf_size - 1) {
            buf[pos] = c;
            pos++;
        } else {
            overflow = true;
        }
    }

    if (overflow) {
        serial_write_string("ERR: input too long, truncated\r\n");
    }

    /* Null-terminate */
    buf[pos] = '\0';
    return pos;
}

